"use client"

// 支払明細（最重要）— 認定損害額 − 過失相殺 − 免責 − 既払金 = 今回支払額
//
// 注: @gunjo/ui に「符号付き加減算の明細＋小計／総計を強調表示する台帳(ledger)」
// 表示コンポーネントは存在しなかった。MetadataList は label/value の対だけ、
// EditableDataTable は編集用、DistributionBar は割合バー。いずれも
// 「加算 → 控除(マイナス) → 小計 → 補償横断の総計 ＋ 計算式の明示」という
// 会計的内訳の意味論を持たない。よって本コンポーネントは手組み。
// kit からは Badge / Separator / formatCurrency を利用。

import { Badge, Separator, formatCurrency } from "@gunjo/ui"

import {
  type CoverageDerivation,
  type DerivationLine,
  type PaymentCase,
  COVERAGE_TONE,
  caseTotal,
  coverageNet,
} from "./data"

const yen = (n: number) => formatCurrency(n)
/** 控除など符号を明示したいとき（+12,300 / −5,000） */
const yenSigned = (n: number) => formatCurrency(n, { signed: true })

function LedgerRow({
  line,
  emphasis = false,
}: {
  line: DerivationLine
  emphasis?: boolean
}) {
  const isDeduction = line.kind === "deduction"
  // 控除はマイナス値。0 の控除は「適用なし」として淡色表示。
  const zero = line.amount === 0
  return (
    <div className="flex items-baseline justify-between gap-3 py-1.5">
      <div className="min-w-0">
        <span
          className={
            "text-sm " + (zero ? "text-muted-foreground" : "text-foreground")
          }
        >
          {line.label}
        </span>
        {line.note ? (
          <span className="ml-2 text-xs text-muted-foreground">（{line.note}）</span>
        ) : null}
      </div>
      <span
        className={
          "shrink-0 tabular-nums " +
          (emphasis ? "text-sm font-semibold " : "text-sm ") +
          (zero
            ? "text-muted-foreground"
            : isDeduction
              ? "text-destructive"
              : "text-foreground")
        }
      >
        {isDeduction && !zero ? yenSigned(line.amount) : yen(line.amount)}
      </span>
    </div>
  )
}

function CoverageLedger({ d }: { d: CoverageDerivation }) {
  const dmgTotal = d.damages.reduce((s, l) => s + l.amount, 0)
  const net = coverageNet(d)

  return (
    <section
      className="rounded-lg border border-border bg-card p-4"
      aria-label={`${d.coverage} 支払明細`}
    >
      <div className="mb-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <Badge variant={COVERAGE_TONE[d.coverage]}>{d.coverage}</Badge>
          <span className="text-sm font-medium text-foreground">補償の支払導出</span>
        </div>
        <span className="text-xs text-muted-foreground">支払先：{d.payee.kind}</span>
      </div>

      {/* 認定損害額（加算） */}
      <div role="group" aria-label="認定損害額の内訳">
        <p className="mb-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
          認定損害額
        </p>
        {d.damages.map((l, i) => (
          <LedgerRow key={i} line={l} />
        ))}
        <div className="mt-1 flex items-baseline justify-between gap-3 border-t border-dashed border-border pt-1.5">
          <span className="text-sm font-medium text-foreground">認定損害額 小計</span>
          <span className="shrink-0 text-sm font-semibold tabular-nums text-foreground">
            {yen(dmgTotal)}
          </span>
        </div>
      </div>

      <Separator className="my-3" />

      {/* 控除 */}
      <div role="group" aria-label="控除の内訳">
        <p className="mb-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
          控除（過失相殺・免責・既払金）
        </p>
        {d.deductions.map((l, i) => (
          <LedgerRow key={i} line={l} />
        ))}
      </div>

      <Separator className="my-3" />

      {/* 補償ごとの今回支払額 */}
      <div className="flex items-baseline justify-between gap-3 rounded-md bg-muted/40 px-3 py-2">
        <span className="text-sm font-semibold text-foreground">
          {d.coverage}：今回支払額
        </span>
        <span className="shrink-0 text-base font-bold tabular-nums text-foreground">
          {yen(net)}
        </span>
      </div>

      <p className="mt-2 text-xs text-muted-foreground">
        支払先：{d.payee.name} ／ {d.payee.bank}
      </p>
    </section>
  )
}

export function PaymentDerivation({ paymentCase }: { paymentCase: PaymentCase }) {
  const total = caseTotal(paymentCase)

  return (
    <div className="space-y-4">
      {/* 計算式の明示 */}
      <div
        className="rounded-md border border-border bg-muted/30 px-3 py-2 text-xs text-muted-foreground"
        aria-label="支払額の計算式"
      >
        <span className="font-medium text-foreground">今回支払額</span>
        {" ＝ 認定損害額 − 過失相殺 − 免責金額 − 既払金（内払）"}
      </div>

      {paymentCase.derivations.map((d) => (
        <CoverageLedger key={d.coverage} d={d} />
      ))}

      {/* 補償横断の支払総額（強調） */}
      <div className="flex items-center justify-between gap-3 rounded-lg border-2 border-foreground/80 bg-card px-4 py-3">
        <div>
          <p className="text-sm font-semibold text-foreground">支払総額</p>
          <p className="text-xs text-muted-foreground">
            {paymentCase.derivations.length} 補償の今回支払額合計
          </p>
        </div>
        <span className="text-2xl font-bold tabular-nums text-foreground">
          {yen(total)}
        </span>
      </div>
    </div>
  )
}

